import styled from "styled-components";

export const TaskWrapper = styled.li`
  list-style-type: none;
  text-align: start;
  display: flex;
  justify-content: space-between;
  padding: 10px;
`

export const TaskText = styled.span`
  font-size: 20px;
  font-family: 'Roboto';
  cursor: pointer;
`
export const TaskDell = styled.button`
  border: none;
  background: white;
  cursor: pointer;
  transition: 0.7s;

  &:hover {
      background: red;
      color: white;
      padding: 10px;
      transition: 0.7s;
     cursor: pointer;
  }
`
